#!/usr/bin/env node
// @author kongweiguang

import { execFileSync } from "node:child_process";
import { mkdirSync, writeFileSync } from "node:fs";
import { platform } from "node:os";
import path from "node:path";
import { performance } from "node:perf_hooks";
import { fileURLToPath } from "node:url";

const repoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const args = parseArgs(process.argv.slice(2));
const outputPath = path.resolve(
  repoRoot,
  args.output ?? ".updeng/docs/verification/perf-ai-streaming-baseline.json",
);
const config = {
  deltaCount: readPositiveInteger(args.deltas, 1000, "--deltas"),
  deltaIntervalMs: readNonNegativeInteger(
    args["delta-interval-ms"],
    12,
    "--delta-interval-ms",
  ),
  deltaSize: readPositiveInteger(args["delta-size"], 16, "--delta-size"),
  flushDelayMs: readPositiveInteger(
    args["flush-delay-ms"],
    32,
    "--flush-delay-ms",
  ),
  stepCount: readNonNegativeInteger(args.steps, 20, "--steps"),
};

const result = runBaseline(config);
const bufferedResult = runBufferedStreaming(config);
const report = {
  schemaVersion: 1,
  generatedAt: new Date().toISOString(),
  git: readGitMetadata(),
  environment: {
    node: process.version,
    platform: platform(),
  },
  config,
  aiStreaming: result,
  bufferedAiStreaming: bufferedResult,
  summary: {
    bufferedLocalStorageWrites: bufferedResult.localStorageWrites,
    bufferedStateUpdates: bufferedResult.stateUpdates,
    contentMatches: result.contentMatches && bufferedResult.contentMatches,
    elapsedMs: result.elapsedMs,
    localStorageWrites: result.localStorageWrites,
    localStorageWriteReduction:
      result.localStorageWrites - bufferedResult.localStorageWrites,
    pass: result.contentMatches && bufferedResult.contentMatches,
    stateUpdateReduction: result.stateUpdates - bufferedResult.stateUpdates,
    stateUpdates: result.stateUpdates,
  },
};

mkdirSync(path.dirname(outputPath), { recursive: true });
writeFileSync(outputPath, `${JSON.stringify(report, null, 2)}\n`, "utf8");

console.log(
  `AI streaming baseline: ${result.deltaCount} deltas, ${result.stateUpdates} state updates, ${result.localStorageWrites} persistence writes, ${result.elapsedMs.toFixed(
    2,
  )} ms.`,
);
console.log(
  `AI streaming buffered: ${bufferedResult.deltaCount} deltas, ${bufferedResult.stateUpdates} state updates, ${bufferedResult.localStorageWrites} persistence writes, ${bufferedResult.elapsedMs.toFixed(
    2,
  )} ms.`,
);
console.log(`Report: ${path.relative(repoRoot, outputPath).replaceAll("\\", "/")}`);

if (!report.summary.pass) {
  process.exitCode = 1;
}

function runBaseline({ deltaCount, deltaSize, stepCount }) {
  const deltas = buildDeltas(deltaCount, deltaSize);
  const expectedContent = deltas.join("");
  const heapStartBytes = process.memoryUsage().heapUsed;
  let state = {
    messages: [
      {
        content: "",
        id: "assistant-baseline",
        role: "assistant",
      },
    ],
    steps: [],
  };
  let localStorageWrites = 0;
  let serializedBytes = 0;
  let stateUpdates = 0;

  const startedAt = performance.now();
  for (const delta of deltas) {
    state = {
      ...state,
      messages: [
        {
          ...state.messages[0],
          content: state.messages[0].content + delta,
        },
      ],
    };
    stateUpdates += 1;
    serializedBytes += persistState(state);
    localStorageWrites += 1;
  }

  for (let index = 0; index < stepCount; index += 1) {
    state = {
      ...state,
      steps: [
        ...state.steps,
        {
          id: `step-${index + 1}`,
          status: index % 2 === 0 ? "running" : "completed",
          summary: `Synthetic tool step ${index + 1}`,
        },
      ],
    };
    stateUpdates += 1;
    serializedBytes += persistState(state);
    localStorageWrites += 1;
  }

  const elapsedMs = performance.now() - startedAt;
  const heapEndBytes = process.memoryUsage().heapUsed;
  const finalContent = state.messages[0].content;

  return {
    contentMatches: finalContent === expectedContent,
    deltaCount,
    deltaSize,
    elapsedMs,
    finalBytes: Buffer.byteLength(finalContent),
    heap: {
      deltaBytes: heapEndBytes - heapStartBytes,
      endBytes: heapEndBytes,
      startBytes: heapStartBytes,
    },
    localStorageWrites,
    serializedBytes,
    stateUpdates,
    stepCount,
  };
}

function runBufferedStreaming({
  deltaCount,
  deltaIntervalMs,
  deltaSize,
  flushDelayMs,
  stepCount,
}) {
  const deltas = buildDeltas(deltaCount, deltaSize);
  const expectedContent = deltas.join("");
  const heapStartBytes = process.memoryUsage().heapUsed;
  let state = {
    messages: [
      {
        content: "",
        id: "assistant-buffered",
        role: "assistant",
      },
    ],
    steps: [],
  };
  let pendingDelta = "";
  let elapsedSinceFlushMs = 0;
  let stateUpdates = 0;

  const flushDelta = () => {
    if (!pendingDelta) {
      return;
    }
    state = {
      ...state,
      messages: [
        {
          ...state.messages[0],
          content: state.messages[0].content + pendingDelta,
        },
      ],
    };
    pendingDelta = "";
    elapsedSinceFlushMs = 0;
    stateUpdates += 1;
  };

  const startedAt = performance.now();
  for (const delta of deltas) {
    pendingDelta += delta;
    elapsedSinceFlushMs += deltaIntervalMs;
    if (elapsedSinceFlushMs >= flushDelayMs) {
      flushDelta();
    }
  }

  for (let index = 0; index < stepCount; index += 1) {
    flushDelta();
    state = {
      ...state,
      steps: [
        ...state.steps,
        {
          id: `step-${index + 1}`,
          status: index % 2 === 0 ? "running" : "completed",
          summary: `Synthetic tool step ${index + 1}`,
        },
      ],
    };
    stateUpdates += 1;
  }
  flushDelta();

  const serializedBytes = persistState(state);
  const elapsedMs = performance.now() - startedAt;
  const heapEndBytes = process.memoryUsage().heapUsed;
  const finalContent = state.messages[0].content;

  return {
    contentMatches: finalContent === expectedContent,
    deltaCount,
    deltaIntervalMs,
    deltaSize,
    elapsedMs,
    finalBytes: Buffer.byteLength(finalContent),
    flushDelayMs,
    heap: {
      deltaBytes: heapEndBytes - heapStartBytes,
      endBytes: heapEndBytes,
      startBytes: heapStartBytes,
    },
    localStorageWrites: finalContent || state.steps.length > 0 ? 1 : 0,
    serializedBytes,
    stateUpdates,
    stepCount,
  };
}

function buildDeltas(deltaCount, deltaSize) {
  return Array.from({ length: deltaCount }, (_, index) => {
    const prefix = `${(index % 100).toString().padStart(2, "0")}:`;
    return `${prefix}${"x".repeat(Math.max(0, deltaSize - prefix.length))}`;
  });
}

function persistState(value) {
  return Buffer.byteLength(JSON.stringify(value));
}

function parseArgs(rawArgs) {
  const parsed = {};
  for (let index = 0; index < rawArgs.length; index += 1) {
    const arg = rawArgs[index];
    if (!arg.startsWith("--")) {
      continue;
    }
    const key = arg.slice(2);
    const value = rawArgs[index + 1];
    if (!value || value.startsWith("--")) {
      parsed[key] = true;
      continue;
    }
    parsed[key] = value;
    index += 1;
  }
  return parsed;
}

function readPositiveInteger(value, fallback, label) {
  const parsed = value === undefined ? fallback : Number.parseInt(value, 10);
  if (!Number.isInteger(parsed) || parsed <= 0) {
    throw new Error(`${label} must be a positive integer.`);
  }
  return parsed;
}

function readNonNegativeInteger(value, fallback, label) {
  const parsed = value === undefined ? fallback : Number.parseInt(value, 10);
  if (!Number.isInteger(parsed) || parsed < 0) {
    throw new Error(`${label} must be a non-negative integer.`);
  }
  return parsed;
}

function readGitMetadata() {
  return {
    branch: runGit(["rev-parse", "--abbrev-ref", "HEAD"]),
    commit: runGit(["rev-parse", "--short", "HEAD"]),
    dirty: runGit(["status", "--short"]) !== "",
  };
}

function runGit(argsForGit) {
  try {
    return execFileSync("git", argsForGit, {
      cwd: repoRoot,
      encoding: "utf8",
      stdio: ["ignore", "pipe", "ignore"],
    }).trim();
  } catch {
    return null;
  }
}

