const dateStamp = new Date().toISOString().slice(0, 10).replaceAll("-", "");
const outputPath = path.resolve(
  repoRoot,
  args.output ?? `.updeng/docs/verification/performance-baseline-${dateStamp}.json`,
);
const verificationDir = path.join(repoRoot, ".updeng", "docs", "verification");

const report = {
  schemaVersion: 1,
  generatedAt: new Date().toISOString(),
  git: readGitMetadata(),
  environment: {
    node: process.version,
    platform: platform(),
  },
  reports: {
    aiStreaming: readReport("perf-ai-streaming-baseline.json"),
    directoryList: readReport("perf-directory-list-baseline.json"),
    frontendBundle: readReport("frontend-bundle-baseline.json"),
    terminalOutput: readReport("terminal-output-baseline.json"),
  },
  rustTimings: latestCargoTimingReport(),
};

report.summary = {
  aiStreamingPass: report.reports.aiStreaming?.summary?.pass ?? null,
  directoryListPass: report.reports.directoryList?.summary?.pass ?? null,
  frontendAssetCount: report.reports.frontendBundle?.assetCount ?? null,
  frontendRawBytes: report.reports.frontendBundle?.totals?.bytes ?? null,
  latestCargoTimingReport: report.rustTimings?.path ?? null,
  pass:
    report.reports.aiStreaming?.summary?.pass === true &&
    report.reports.directoryList?.summary?.pass === true &&
    report.reports.terminalOutput?.summary?.pass === true &&
    Boolean(report.reports.frontendBundle),
  terminalOutputPass: report.reports.terminalOutput?.summary?.pass ?? null,
};

mkdirSync(path.dirname(outputPath), { recursive: true });
writeFileSync(outputPath, `${JSON.stringify(report, null, 2)}\n`, "utf8");

console.log(`Performance baseline summary: ${report.summary.pass ? "pass" : "incomplete"}.`);
console.log(`Report: ${path.relative(repoRoot, outputPath).replaceAll("\\", "/")}`);

if (!report.summary.pass) {
  process.exitCode = 1;
}

function readReport(fileName) {
  const filePath = path.join(verificationDir, fileName);
  if (!existsSync(filePath)) {
    return null;
  }
  return JSON.parse(readFileSync(filePath, "utf8"));
}

function latestCargoTimingReport() {
  const timingDir = path.join(repoRoot, "src-tauri", "target", "cargo-timings");
  if (!existsSync(timingDir)) {
    return null;
  }
  const latest = readdirSync(timingDir)
    .filter((fileName) => fileName.endsWith(".html") && fileName !== "cargo-timing.html")
    .map((fileName) => {
      const filePath = path.join(timingDir, fileName);
      return {
        fileName,
        filePath,
        stat: statSync(filePath),
      };
    })
    .sort((left, right) => right.stat.mtimeMs - left.stat.mtimeMs)[0];
  if (!latest) {
    return null;
  }
  return {
    generatedAt: latest.stat.mtime.toISOString(),
    path: path.relative(repoRoot, latest.filePath).replaceAll("\\", "/"),
    sizeBytes: latest.stat.size,
  };
}

function parseArgs(rawArgs) {
  const parsed = {};
  for (let index = 0; index < rawArgs.length; index += 1) {
    const arg = rawArgs[index];
    if (!arg.startsWith("--")) {
      continue;
    }
    const key = arg.slice(2);
    const value = rawArgs[index + 1];
    if (!value || value.startsWith("--")) {
      parsed[key] = true;
      continue;
    }
    parsed[key] = value;
    index += 1;
  }
  return parsed;
}

function readGitMetadata() {
  return {
    branch: runGit(["rev-parse", "--abbrev-ref", "HEAD"]),
    commit: runGit(["rev-parse", "--short", "HEAD"]),
    dirty: runGit(["status", "--short"]) !== "",
  };
}

function runGit(argsForGit) {
  try {
    return execFileSync("git", argsForGit, {
      cwd: repoRoot,
      encoding: "utf8",
      stdio: ["ignore", "pipe", "ignore"],
    }).trim();
  } catch {
    return null;
  }
}

#!/usr/bin/env node
// @author kongweiguang

import { execFileSync } from "node:child_process";
import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { platform } from "node:os";
import path from "node:path";
import { performance } from "node:perf_hooks";
import { fileURLToPath } from "node:url";

const repoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const args = parseArgs(process.argv.slice(2));
const outputPath = path.resolve(
  repoRoot,
  args.output ?? ".updeng/docs/verification/perf-directory-list-baseline.json",
);
const config = {
  counts: readIntegerList(args.counts ?? "200,1000,5000", "--counts"),
  overscan: readInteger(args.overscan ?? "8", "--overscan"),
  rowHeight: readInteger(args.rowHeight ?? "44", "--row-height"),
  targets: readTargetList(args.targets ?? "sftp,local"),
  threshold: readInteger(args.threshold ?? "120", "--threshold"),
  viewportRows: readInteger(args.viewportRows ?? "14", "--viewport-rows"),
};

const { JSDOM } = await import("jsdom");
const results = [];
for (const target of config.targets) {
  for (const entryCount of config.counts) {
    results.push(measureDirectoryRender({ entryCount, target }));
  }
}

const report = {
  schemaVersion: 1,
  generatedAt: new Date().toISOString(),
  git: readGitMetadata(),
  environment: {
    jsdom: readPackageVersion("jsdom"),
    node: process.version,
    platform: platform(),
  },
  config,
  directoryList: results,
  summary: {
    maxDomNodeCount: Math.max(...results.map((result) => result.domNodeCount)),
    maxElapsedMs: Math.max(...results.map((result) => result.elapsedMs)),
    pass: results.every((result) => result.virtualizationSmoke && result.selectedRowSmoke),
    resultCount: results.length,
  },
};

mkdirSync(path.dirname(outputPath), { recursive: true });
writeFileSync(outputPath, `${JSON.stringify(report, null, 2)}\n`, "utf8");

console.log(
  `Directory list baseline: ${results.length} runs, max ${report.summary.maxElapsedMs.toFixed(
    2,
  )} ms, max ${report.summary.maxDomNodeCount} DOM nodes.`,
);
console.log(`Report: ${path.relative(repoRoot, outputPath).replaceAll("\\", "/")}`);

if (!report.summary.pass) {
  process.exitCode = 1;
}

function measureDirectoryRender({ entryCount, target }) {
  const entries = target === "sftp" ? buildSftpEntries(entryCount) : buildLocalEntries(entryCount);
  const dom = new JSDOM("<!doctype html><main id=\"root\"></main>");
  const document = dom.window.document;
  const root = document.getElementById("root");
  const heapStartBytes = process.memoryUsage().heapUsed;
  const startedAt = performance.now();
  const fragment = document.createDocumentFragment();
  const virtualized = entryCount > config.threshold;
  const midpoint = Math.floor(entryCount / 2);
  const viewportHeight = config.viewportRows * config.rowHeight;
  const virtualWindow = virtualized
    ? resolveVirtualFixedListWindow({
        itemCount: entryCount,
        overscan: config.overscan,
        rowHeight: config.rowHeight,
        scrollTop: midpoint * config.rowHeight,
        viewportHeight,
      })
    : {
        bottomSpacerHeight: 0,
        endIndexExclusive: entryCount,
        startIndex: 0,
        topSpacerHeight: 0,
      };
  const renderedEntries = entries.slice(
    virtualWindow.startIndex,
    virtualWindow.endIndexExclusive,
  );

  if (virtualized && virtualWindow.topSpacerHeight > 0) {
    fragment.appendChild(createSpacer(document, virtualWindow.topSpacerHeight));
  }

  for (const entry of renderedEntries) {
    const row = document.createElement("button");
    row.dataset.entryRow = "true";
    row.dataset.kind = entry.kind;
    row.dataset.path = entry.path;
    row.type = "button";
    row.className = "directory-row";
    row.textContent = `${entry.kind} ${entry.name} ${entry.size} ${entry.modifiedAt}`;
    fragment.appendChild(row);
  }

  if (virtualized && virtualWindow.bottomSpacerHeight > 0) {
    fragment.appendChild(createSpacer(document, virtualWindow.bottomSpacerHeight));
  }

  root.appendChild(fragment);
  const selected = Array.from(root.querySelectorAll("[data-entry-row]")).find(
    (row) => row.dataset.path === entries[midpoint]?.path,
  );
  if (selected) {
    selected.setAttribute("aria-selected", "true");
  }

  const elapsedMs = performance.now() - startedAt;
  const rows = root.querySelectorAll("[data-entry-row]");
  const heapEndBytes = process.memoryUsage().heapUsed;
  const selectedRowSmoke = selected?.getAttribute("aria-selected") === "true";
  const result = {
    domNodeCount: root.querySelectorAll("*").length,
    elapsedMs,
    entryCount,
    heap: {
      deltaBytes: heapEndBytes - heapStartBytes,
      endBytes: heapEndBytes,
      startBytes: heapStartBytes,
    },
    maxExpectedRenderedRows: virtualized
      ? config.viewportRows + config.overscan * 2
      : entryCount,
    renderedRows: rows.length,
    selectedRowSmoke,
    target,
    virtualized,
    virtualizationSmoke: virtualized
      ? rows.length <= config.viewportRows + config.overscan * 2
      : rows.length === entryCount,
  };

  dom.window.close();
  return result;
}

function resolveVirtualFixedListWindow({
  itemCount,
  overscan,
  rowHeight,
  scrollTop,
  viewportHeight,
}) {
  const totalHeight = itemCount * rowHeight;
  const maxScrollTop = Math.max(0, totalHeight - Math.max(0, viewportHeight));
  const clampedScrollTop = Math.min(maxScrollTop, Math.max(0, scrollTop));
  const firstVisibleIndex = Math.min(
    Math.max(0, itemCount - 1),
    Math.floor(clampedScrollTop / rowHeight),
  );
  const visibleCount = Math.max(1, Math.ceil(Math.max(0, viewportHeight) / rowHeight));
  const startIndex = Math.max(0, firstVisibleIndex - overscan);
  const endIndexExclusive = Math.min(
    itemCount,
    firstVisibleIndex + visibleCount + overscan,
  );

  return {
    bottomSpacerHeight: Math.max(0, (itemCount - endIndexExclusive) * rowHeight),
    endIndexExclusive,
    startIndex,
    topSpacerHeight: startIndex * rowHeight,
  };
}

function createSpacer(document, height) {
  const spacer = document.createElement("div");
  spacer.dataset.virtualSpacer = "true";
  spacer.style.height = `${height}px`;
  return spacer;
}

function buildSftpEntries(count) {
  return Array.from({ length: count }, (_, index) => {
    const isDirectory = index % 9 === 0;
    return {
      kind: isDirectory ? "directory" : "file",
      modifiedAt: `2026-06-${((index % 28) + 1).toString().padStart(2, "0")}T12:00:00Z`,
      name: `${isDirectory ? "dir" : "file"}-${index.toString().padStart(5, "0")}`,
      path: `/srv/data/${index.toString().padStart(5, "0")}`,
      size: isDirectory ? 0 : 1024 + index,
    };
  });
}

function buildLocalEntries(count) {
  return Array.from({ length: count }, (_, index) => {
    const isDirectory = index % 7 === 0;
    return {
      kind: isDirectory ? "directory" : "file",
      modifiedAt: `2026-06-${((index % 28) + 1).toString().padStart(2, "0")}T08:00:00Z`,
      name: `${isDirectory ? "folder" : "artifact"}-${index.toString().padStart(5, "0")}`,
      path: `C:/work/data/${index.toString().padStart(5, "0")}`,
      size: isDirectory ? 0 : 2048 + index,
    };
  });
}

function parseArgs(rawArgs) {
  const parsed = {};
  for (let index = 0; index < rawArgs.length; index += 1) {
    const arg = rawArgs[index];
    if (!arg.startsWith("--")) {
      continue;
    }
    const key = arg.slice(2);
    const value = rawArgs[index + 1];
    if (!value || value.startsWith("--")) {
      parsed[key] = true;
      continue;
    }
    parsed[key] = value;
    index += 1;
  }
  return parsed;
}

function readIntegerList(value, label) {
  const parsed = value
    .split(",")
    .map((item) => Number.parseInt(item.trim(), 10))
    .filter((item) => Number.isInteger(item) && item > 0);
  if (parsed.length === 0) {
    throw new Error(`${label} must contain at least one positive integer.`);
  }
  return parsed;
}

function readInteger(value, label) {
  const parsed = Number.parseInt(value, 10);
  if (!Number.isInteger(parsed) || parsed <= 0) {
    throw new Error(`${label} must be a positive integer.`);
  }
  return parsed;
}

function readTargetList(value) {
  const allowed = new Set(["sftp", "local"]);
  const parsed = value
    .split(",")
    .map((item) => item.trim())
    .filter((item) => allowed.has(item));
  if (parsed.length === 0) {
    throw new Error("--targets must include sftp, local, or both.");
  }
  return parsed;
}

function readPackageVersion(packageName) {
  try {
    const packageJsonPath = path.join(repoRoot, "node_modules", packageName, "package.json");
    return JSON.parse(readFileSync(packageJsonPath, "utf8")).version ?? null;
  } catch {
    return null;
  }
}

function readGitMetadata() {
  return {
    branch: runGit(["rev-parse", "--abbrev-ref", "HEAD"]),
    commit: runGit(["rev-parse", "--short", "HEAD"]),
    dirty: runGit(["status", "--short"]) !== "",
  };
}

function runGit(argsForGit) {
  try {
    return execFileSync("git", argsForGit, {
      cwd: repoRoot,
      encoding: "utf8",
      stdio: ["ignore", "pipe", "ignore"],
    }).trim();
  } catch {
    return null;
  }
}

#!/usr/bin/env node
// @author kongweiguang

import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const repoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const args = parseArgs(process.argv.slice(2));
const reportDate = args.date ?? formatDateForFile(new Date());
const terminalBaselinePath = resolveRepoPath(
  args.input ?? args["terminal-baseline"] ?? ".updeng/docs/verification/terminal-output-baseline.json",
);
const performanceBaselinePath = resolveRepoPath(
  args["performance-baseline"] ?? ".updeng/docs/verification/performance-baseline-20260623.json",
);
const outputPath = resolveRepoPath(
  args.output ?? `.updeng/docs/reports/terminal-output-profiling-${reportDate}.md`,
);

if (!existsSync(terminalBaselinePath)) {
  console.error(`Terminal output baseline not found: ${relativePath(terminalBaselinePath)}`);
  process.exit(1);
}

const terminalBaseline = readJson(terminalBaselinePath);
const performanceBaseline = existsSync(performanceBaselinePath) ? readJson(performanceBaselinePath) : null;
const terminalReport = selectTerminalReport(terminalBaseline, performanceBaseline);
const markdown = renderReport({
  performanceBaseline,
  reportDate,
  terminalBaselinePath,
  terminalReport,
});

mkdirSync(path.dirname(outputPath), { recursive: true });
writeFileSync(outputPath, markdown, "utf8");

console.log(`Terminal output profiling report: ${relativePath(outputPath)}`);

function selectTerminalReport(terminalBaseline, performanceBaseline) {
  const nestedTerminal = performanceBaseline?.reports?.terminalOutput;
  if (nestedTerminal?.results?.length) {
    return nestedTerminal;
  }
  return terminalBaseline;
}

function renderReport({ performanceBaseline, reportDate, terminalBaselinePath, terminalReport }) {
  const config = terminalReport.config ?? {};
  const results = Array.isArray(terminalReport.results) ? terminalReport.results : [];
  const summary = terminalReport.summary ?? {};
  const worstByWriteP95 = maxBy(results, (result) => metric(result, "timing.writeCallbackMs.p95"));
  const worstByWriteMax = maxBy(results, (result) => metric(result, "timing.writeCallbackMs.max"));
  const worstByFrame = maxBy(results, (result) => metric(result, "frames.gapMs.max"));
  const worstByLongTask = maxBy(results, (result) => metric(result, "longTasks.maxMs"));
  const totalRemoteSchedules = sum(results, (result) => metric(result, "sideEffects.remotePrewarmSchedules"));
  const totalCwdPaths = sum(results, (result) => metric(result, "sideEffects.cwdPathCount"));
  const totalHistoryFlushes = sum(results, (result) => metric(result, "sideEffects.historyFlushCount"));
  const maxCommandTail = max(results, (result) => metric(result, "sideEffects.commandBlockTailLength"));
  const generatedAt = new Date().toISOString();
  const inputBytes = sum(results, (result) => metric(result, "input.bytes"));
  const lines = [];

  lines.push(`# Terminal Output Profiling Report ${reportDate}`);
  lines.push("");
  lines.push("## Scope");
  lines.push("");
  lines.push("- TASK: TASK-002 terminal large output profiling report.");
  lines.push("- Non-goal: no runtime behavior change, no terminal/workspace/machine-sidebar code edits, no output ordering or side effect semantics changes.");
  lines.push(`- Generated at: ${generatedAt}.`);
  lines.push(`- Input baseline: \`${relativePath(terminalBaselinePath)}\`.`);
  if (performanceBaseline) {
    lines.push(`- Performance baseline: \`${relativePath(performanceBaselinePath)}\`.`);
  } else {
    lines.push(`- Performance baseline: not found at \`${relativePath(performanceBaselinePath)}\`; report uses terminal baseline only.`);
  }
  lines.push("");
  lines.push("## Scenario Input");
  lines.push("");
  lines.push("| Field | Value |");
  lines.push("| --- | --- |");
  lines.push(`| scenarios | ${formatInlineList(config.scenarios)} |`);
  lines.push(`| chunks | ${formatNumber(config.chunks)} |`);
  lines.push(`| chunkSize | ${formatNumber(config.chunkSize)} chars |`);
  lines.push(`| maxCharsPerFlush | ${formatNumber(config.maxCharsPerFlush)} chars |`);
  lines.push(`| viewport | ${formatViewport(config.viewport)} |`);
  lines.push(`| total input | ${formatNumber(inputBytes)} chars across ${results.length} scenarios |`);
  lines.push("");
  lines.push("## Scenario Metrics");
  lines.push("");
  lines.push("| Scenario | Input chars | writeCallback p95 / max | frame gap p95 / max | long tasks | sideEffects counts |");
  lines.push("| --- | ---: | ---: | ---: | ---: | --- |");
  for (const result of results) {
    lines.push(
      `| ${result.scenario ?? "unknown"} | ${formatNumber(metric(result, "input.chars"))} | ${formatMs(
        metric(result, "timing.writeCallbackMs.p95"),
      )} / ${formatMs(metric(result, "timing.writeCallbackMs.max"))} | ${formatMs(
        metric(result, "frames.gapMs.p95"),
      )} / ${formatMs(metric(result, "frames.gapMs.max"))} | ${formatNumber(
        metric(result, "longTasks.count"),
      )} count, max ${formatMs(metric(result, "longTasks.maxMs"))} | ${formatSideEffects(result.sideEffects)} |`,
    );
  }
  lines.push("");
  lines.push("## Initial Judgment");
  lines.push("");
  lines.push(`- Current baseline pass: ${summary.pass === false ? "no" : "yes"}.`);
  lines.push(
    `- Worst write callback p95: ${describeScenario(worstByWriteP95, "timing.writeCallbackMs.p95")}; worst max: ${describeScenario(
      worstByWriteMax,
      "timing.writeCallbackMs.max",
    )}.`,
  );
  lines.push(
    `- Worst frame gap: ${describeScenario(worstByFrame, "frames.gapMs.max")}; long task ceiling: ${describeScenario(
      worstByLongTask,
      "longTasks.maxMs",
    )}.`,
  );
  lines.push(
    `- Side effect pressure is visible in counts before runtime instrumentation: cwd OSC paths ${formatNumber(
      totalCwdPaths,
    )}, remote prewarm schedules ${formatNumber(totalRemoteSchedules)}, history flushes ${formatNumber(
      totalHistoryFlushes,
    )}, command block tail cap ${formatNumber(maxCommandTail)} chars.`,
  );
  lines.push(
    "- The current harness measures real xterm write callback and simulated side effect costs. It does not yet prove the cost distribution inside `XtermPane.runtime.ts` `handleOutput`, so optimization should wait for TASK-006 targeted instrumentation or a behavior-preserving model test.",
  );
  lines.push("");
  lines.push("## TASK-006 Candidates");
  lines.push("");
  lines.push("- Add temporary, feature-flagged measurement around `handleOutput` substeps before changing behavior.");
  lines.push("- Fast-path cwd OSC parsing so ordinary output skips regex work unless an OSC marker is present.");
  lines.push("- Coalesce remote suggestion prewarm scheduling on cwd changes; OSC scenario currently produces one schedule per cwd sequence.");
  lines.push("- Evaluate command block append batching, but only with marker range tests that prove command block color bars remain correct.");
  lines.push("- Evaluate pending-chunk history buffering only if synchronous `outputHistoryRef.current` visibility can be preserved.");
  lines.push("");
  lines.push("## Explicit No-Behavior-Change Contract");
  lines.push("");
  lines.push("- This report generator only reads JSON baselines and writes a Markdown report.");
  lines.push("- It does not import app runtime modules, start Vite/Tauri, modify xterm handling, change store updates, or alter terminal output ordering.");
  lines.push("- Any future TASK-006 optimization must keep terminal output order, cwd sync, command block markers, ghost suggestion prewarm semantics, close/reconnect messages, and history visibility stable.");
  lines.push("");
  lines.push("## Source Summary");
  lines.push("");
  lines.push(`- Terminal baseline generated at: ${terminalReport.generatedAt ?? "unknown"}.`);
  lines.push(`- Environment: Node ${terminalReport.environment?.node ?? "unknown"}, xterm ${terminalReport.environment?.xterm ?? "unknown"}.`);
  if (performanceBaseline?.git) {
    lines.push(
      `- Git baseline: branch ${performanceBaseline.git.branch ?? "unknown"}, commit ${
        performanceBaseline.git.commit ?? "unknown"
      }, dirty ${String(performanceBaseline.git.dirty ?? "unknown")}.`,
    );
  }
  lines.push("");
  return `${lines.join("\n")}\n`;
}

function formatSideEffects(sideEffects = {}) {
  return [
    `cwd ${formatNumber(sideEffects.cwdPathCount)}`,
    `prewarm ${formatNumber(sideEffects.remotePrewarmSchedules)}`,
    `history flush ${formatNumber(sideEffects.historyFlushCount)}`,
    `tail ${formatNumber(sideEffects.commandBlockTailLength)}`,
  ].join(", ");
}

function describeScenario(result, metricPath) {
  if (!result) {
    return "n/a";
  }
  return `${result.scenario ?? "unknown"} ${formatMs(metric(result, metricPath))}`;
}

function metric(value, dottedPath) {
  return dottedPath.split(".").reduce((current, key) => current?.[key], value) ?? 0;
}

function sum(values, selector) {
  return values.reduce((total, value) => total + Number(selector(value) ?? 0), 0);
}

function max(values, selector) {
  if (values.length === 0) {
    return 0;
  }
  return Math.max(...values.map((value) => Number(selector(value) ?? 0)));
}

function maxBy(values, selector) {
  return values.reduce((best, value) => {
    if (!best) {
      return value;
    }
    return Number(selector(value) ?? 0) > Number(selector(best) ?? 0) ? value : best;
  }, null);
}

function formatMs(value) {
  const numeric = Number(value ?? 0);
  return `${numeric.toFixed(2)} ms`;
}

function formatNumber(value) {
  const numeric = Number(value ?? 0);
  return Number.isFinite(numeric) ? numeric.toLocaleString("en-US") : "n/a";
}

function formatInlineList(values) {
  return Array.isArray(values) ? values.map((value) => `\`${value}\``).join(", ") : "n/a";
}

function formatViewport(viewport) {
  if (!viewport?.width || !viewport?.height) {
    return "n/a";
  }
  return `${viewport.width}x${viewport.height}`;
}

function readJson(filePath) {
  return JSON.parse(readFileSync(filePath, "utf8"));
}

function resolveRepoPath(value) {
  return path.resolve(repoRoot, value);
}

function relativePath(filePath) {
  return path.relative(repoRoot, filePath).replaceAll("\\", "/");
}

function formatDateForFile(date) {
  const parts = new Intl.DateTimeFormat("en-CA", {
    day: "2-digit",
    month: "2-digit",
    timeZone: "Asia/Shanghai",
    year: "numeric",
  })
    .formatToParts(date)
    .reduce((accumulator, part) => {
      accumulator[part.type] = part.value;
      return accumulator;
    }, {});
  return `${parts.year}${parts.month}${parts.day}`;
}

function parseArgs(rawArgs) {
  const parsed = {};
  for (let index = 0; index < rawArgs.length; index += 1) {
    const arg = rawArgs[index];
    if (!arg.startsWith("--")) {
      continue;
    }
    const key = arg.slice(2);
    const value = rawArgs[index + 1];
    if (!value || value.startsWith("--")) {
      parsed[key] = true;
      continue;
    }
    parsed[key] = value;
    index += 1;
  }
  return parsed;
}

#!/usr/bin/env node
// @author kongweiguang

import { spawn } from "node:child_process";
import { createReadStream, existsSync, mkdirSync, readFileSync, rmSync, writeFileSync } from "node:fs";
import http from "node:http";
import { tmpdir } from "node:os";
import path from "node:path";
import { fileURLToPath } from "node:url";

const repoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const args = parseArgs(process.argv.slice(2));
const outputPath = path.resolve(
  repoRoot,
  args.output ?? ".updeng/docs/verification/terminal-output-baseline.json",
);
const screenshotPath = outputPath.replace(/\.json$/i, ".png");
const config = {
  chunkSize: readPositiveInteger(args["chunk-size"], 4096, "--chunk-size"),
  chunks: readPositiveInteger(args.chunks, 400, "--chunks"),
  maxCharsPerFlush: readPositiveInteger(args["max-chars-per-flush"], 64 * 1024, "--max-chars-per-flush"),
  scenarios: readScenarios(args.scenario ?? args.scenarios ?? "plain,osc,long-line,mixed"),
  screenshot: Boolean(args.screenshot),
  viewport: readViewport(args.viewport ?? "1280x860"),
};
const chromePath = findChromePath();
const chromePort = 9450 + Math.floor(Math.random() * 300);
const userDataDir = path.join(tmpdir(), `kerminal-terminal-output-perf-${Date.now()}`);
const xtermModulePath = path.join(repoRoot, "node_modules", "@xterm", "xterm", "lib", "xterm.mjs");
const xtermCssPath = path.join(repoRoot, "node_modules", "@xterm", "xterm", "css", "xterm.css");

if (!chromePath) {
  console.error("Chrome executable not found. Set CHROME_PATH to run this baseline.");
  process.exit(1);
}

if (!existsSync(xtermModulePath) || !existsSync(xtermCssPath)) {
  console.error("@xterm/xterm browser assets not found. Run npm install first.");
  process.exit(1);
}

async function main() {
  const assetServer = await startAssetServer();
  const assetPort = assetServer.address().port;
  const chrome = spawn(
    chromePath,
    [
      "--headless=new",
      "--disable-background-networking",
      "--disable-default-apps",
      "--disable-extensions",
      "--disable-gpu",
      "--disable-sync",
      "--hide-scrollbars",
      "--mute-audio",
      "--no-first-run",
      "--no-default-browser-check",
      `--remote-debugging-port=${chromePort}`,
      `--user-data-dir=${userDataDir}`,
      "about:blank",
    ],
    {
      stdio: ["ignore", "ignore", "pipe"],
      windowsHide: true,
    },
  );

  let stderr = "";
  chrome.stderr.on("data", (chunk) => {
    stderr += String(chunk);
  });

  let client;
  try {
    await waitForChrome(chromePort, chrome);
    const target = await requestJson(chromePort, "/json/new?about:blank", "PUT");
    client = await CdpClient.connect(target.webSocketDebuggerUrl);
    await client.send("Runtime.enable");
    await client.send("Page.enable");
    await client.send("Emulation.setDeviceMetricsOverride", {
      deviceScaleFactor: 1,
      height: config.viewport.height,
      mobile: false,
      width: config.viewport.width,
    });
    await client.send("Page.navigate", {
      url: `http://127.0.0.1:${assetPort}/`,
    });
    await waitForBrowserExpression(client, "window.__terminalOutputPerfReady === true");
    const evaluated = await evaluate(client, `window.runKerminalTerminalOutputPerf(${JSON.stringify(config)})`);
    const value = evaluated.result?.value;
    if (!value) {
      throw new Error("Terminal output baseline returned no value.");
    }

    const report = {
      schemaVersion: 1,
      generatedAt: new Date().toISOString(),
      environment: {
        chromePath,
        node: process.version,
        xterm: readPackageVersion("@xterm/xterm"),
      },
      config,
      results: value.results,
      summary: value.summary,
      artifacts: {
        json: path.relative(repoRoot, outputPath).replaceAll("\\", "/"),
      },
    };

    if (config.screenshot) {
      const screenshot = await client.send("Page.captureScreenshot", {
        captureBeyondViewport: true,
        format: "png",
        fromSurface: true,
      });
      mkdirSync(path.dirname(screenshotPath), { recursive: true });
      writeFileSync(screenshotPath, Buffer.from(screenshot.data, "base64"));
      report.artifacts.screenshot = path.relative(repoRoot, screenshotPath).replaceAll("\\", "/");
    }

    mkdirSync(path.dirname(outputPath), { recursive: true });
    writeFileSync(outputPath, `${JSON.stringify(report, null, 2)}\n`, "utf8");

    console.log(
      `Terminal output baseline: ${report.results.length} scenarios, max frame gap ${report.summary.maxFrameGapMs.toFixed(
        2,
      )} ms, max long task ${report.summary.maxLongTaskMs.toFixed(2)} ms.`,
    );
    console.log(`Report: ${path.relative(repoRoot, outputPath).replaceAll("\\", "/")}`);
    if (!report.summary.pass) {
      process.exitCode = 1;
    }
  } catch (error) {
    console.error(error instanceof Error ? error.message : String(error));
    if (stderr.trim()) {
      console.error(stderr.trim());
    }
    process.exitCode = 1;
  } finally {
    client?.close();
    await closeServer(assetServer);
    await terminateChrome(chrome);
    rmSync(userDataDir, {
      force: true,
      maxRetries: 5,
      recursive: true,
      retryDelay: 100,
    });
  }
}

function startAssetServer() {
  const server = http.createServer((request, response) => {
    const url = new URL(request.url ?? "/", "http://127.0.0.1");
    if (url.pathname === "/") {
      response.writeHead(200, {
        "content-type": "text/html; charset=utf-8",
      });
      response.end(terminalOutputHtml());
      return;
    }
    if (url.pathname === "/xterm.mjs") {
      streamFile(response, xtermModulePath, "text/javascript; charset=utf-8");
      return;
    }
    if (url.pathname === "/xterm.css") {
      streamFile(response, xtermCssPath, "text/css; charset=utf-8");
      return;
    }
    response.writeHead(404, {
      "content-type": "text/plain; charset=utf-8",
    });
    response.end("Not found");
  });

  return new Promise((resolve, reject) => {
    server.once("error", reject);
    server.listen(0, "127.0.0.1", () => {
      server.off("error", reject);
      resolve(server);
    });
  });
}

function streamFile(response, filePath, contentType) {
  response.writeHead(200, {
    "cache-control": "no-store",
    "content-type": contentType,
  });
  createReadStream(filePath).pipe(response);
}

function closeServer(server) {
  return new Promise((resolve) => {
    server.close(() => resolve());
  });
}

function findChromePath() {
  const candidates = [
    process.env.CHROME_PATH,
    path.join(process.env.PROGRAMFILES ?? "C:\\Program Files", "Google", "Chrome", "Application", "chrome.exe"),
    path.join(
      process.env["PROGRAMFILES(X86)"] ?? "C:\\Program Files (x86)",
      "Google",
      "Chrome",
      "Application",
      "chrome.exe",
    ),
  ].filter(Boolean);
  return candidates.find((candidate) => Boolean(candidate) && existsSync(candidate));
}

function requestJson(portNumber, pathname, method = "GET") {
  return new Promise((resolve, reject) => {
    const request = http.request(
      {
        hostname: "127.0.0.1",
        method,
        path: pathname,
        port: portNumber,
      },
      (response) => {
        let body = "";
        response.setEncoding("utf8");
        response.on("data", (chunk) => {
          body += chunk;
        });
        response.on("end", () => {
          if ((response.statusCode ?? 500) >= 400) {
            reject(new Error(`Chrome DevTools HTTP ${response.statusCode}: ${body}`));
            return;
          }
          try {
            resolve(JSON.parse(body));
          } catch (error) {
            reject(error);
          }
        });
      },
    );
    request.on("error", reject);
    request.end();
  });
}

async function waitForChrome(portNumber, processHandle) {
  const startedAt = Date.now();
  while (Date.now() - startedAt < 10_000) {
    if (processHandle.exitCode !== null) {
      throw new Error(`Chrome exited with code ${processHandle.exitCode}`);
    }
    try {
      await requestJson(portNumber, "/json/version");
      return;
    } catch {
      await delay(100);
    }
  }
  throw new Error("Timed out waiting for Chrome DevTools.");
}

function waitForBrowserExpression(client, expression) {
  const startedAt = Date.now();
  return new Promise((resolve, reject) => {
    const tick = async () => {
      try {
        const result = await evaluate(client, expression);
        if (result.result?.value) {
          resolve();
          return;
        }
      } catch {
        // Retry until timeout.
      }
      if (Date.now() - startedAt > 10_000) {
        reject(new Error(`Timed out waiting for browser expression: ${expression}`));
        return;
      }
      setTimeout(tick, 100);
    };
    tick();
  });
}

function evaluate(client, expression) {
  return client.send("Runtime.evaluate", {
    awaitPromise: true,
    expression,
    returnByValue: true,
  });
}

function delay(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function terminateChrome(processHandle) {
  return new Promise((resolve) => {
    if (processHandle.exitCode !== null) {
      resolve();
      return;
    }
    const timer = setTimeout(() => {
      processHandle.kill("SIGKILL");
      resolve();
    }, 2000);
    processHandle.once("exit", () => {
      clearTimeout(timer);
      resolve();
    });
    processHandle.kill();
  });
}

class CdpClient {
  static connect(webSocketUrl) {
    return new Promise((resolve, reject) => {
      const ws = new WebSocket(webSocketUrl);
      const client = new CdpClient(ws);
      ws.addEventListener("open", () => resolve(client), { once: true });
      ws.addEventListener("error", reject, { once: true });
    });
  }

  constructor(ws) {
    this.ws = ws;
    this.nextId = 1;
    this.pending = new Map();
    ws.addEventListener("message", (event) => {
      const message = JSON.parse(event.data);
      if (!message.id) {
        return;
      }
      const pending = this.pending.get(message.id);
      if (!pending) {
        return;
      }
      this.pending.delete(message.id);
      if (message.error) {
        pending.reject(new Error(JSON.stringify(message.error)));
      } else {
        pending.resolve(message.result);
      }
    });
  }

  send(method, params = {}) {
    const id = this.nextId;
    this.nextId += 1;
    const message = { id, method, params };
    return new Promise((resolve, reject) => {
      this.pending.set(id, { reject, resolve });
      this.ws.send(JSON.stringify(message));
    });
  }

  close() {
    this.ws.close();
  }
}

function parseArgs(rawArgs) {
  const parsed = {};
  for (let index = 0; index < rawArgs.length; index += 1) {
    const arg = rawArgs[index];
    if (!arg.startsWith("--")) {
      continue;
    }
    const key = arg.slice(2);
    const value = rawArgs[index + 1];
    if (!value || value.startsWith("--")) {
      parsed[key] = true;
      continue;
    }
    parsed[key] = value;
    index += 1;
  }
  return parsed;
}

function readPositiveInteger(value, fallback, label) {
  const parsed = value === undefined ? fallback : Number.parseInt(value, 10);
  if (!Number.isInteger(parsed) || parsed <= 0) {
    throw new Error(`${label} must be a positive integer.`);
  }
  return parsed;
}

function readScenarios(value) {
  const allowed = new Set(["plain", "osc", "long-line", "mixed"]);
  const scenarios = value
    .split(",")
    .map((scenario) => scenario.trim())
    .filter((scenario) => allowed.has(scenario));
  if (scenarios.length === 0) {
    throw new Error("--scenario must include one of plain, osc, long-line, mixed.");
  }
  return scenarios;
}

function readViewport(value) {
  const [width, height] = value.split("x").map((part) => Number.parseInt(part, 10));
  if (!Number.isInteger(width) || !Number.isInteger(height) || width <= 0 || height <= 0) {
    throw new Error("--viewport must use WIDTHxHEIGHT, for example 1280x860.");
  }
  return { height, width };
}

function readPackageVersion(packageName) {
  try {
    const packageJson = JSON.parse(readFileSync(path.join(repoRoot, "node_modules", packageName, "package.json"), "utf8"));
    return packageJson.version ?? null;
  } catch {
    return null;
  }
}

function terminalOutputHtml() {
  return `<!doctype html>
<html>
<head>
  <meta charset="utf-8" />
  <link rel="stylesheet" href="/xterm.css" />
  <style>
    body { margin: 0; background: #111827; color: #e5e7eb; font-family: sans-serif; }
    #terminal { width: 100vw; height: 100vh; padding: 16px; box-sizing: border-box; }
  </style>
</head>
<body>
  <div id="terminal"></div>
  <script type="module">
    import { Terminal } from "/xterm.mjs";

    window.__terminalOutputPerfReady = true;
    window.runKerminalTerminalOutputPerf = async function runKerminalTerminalOutputPerf(config) {
      const results = [];
      for (const scenario of config.scenarios) {
        results.push(await runScenario(scenario, config));
      }
      const maxFrameGapMs = Math.max(...results.map((result) => result.frames.gapMs.max));
      const maxLongTaskMs = Math.max(...results.map((result) => result.longTasks.maxMs));
      return {
        results,
        summary: {
          maxFrameGapMs,
          maxLongTaskMs,
          pass: results.every((result) => result.pass),
          worstScenario: results.toSorted((left, right) => right.timing.totalMs - left.timing.totalMs)[0]?.scenario ?? null,
        },
      };
    };

    async function runScenario(scenario, config) {
      const container = document.getElementById("terminal");
      container.textContent = "";
      const terminal = new Terminal({
        cols: 120,
        convertEol: true,
        disableStdin: true,
        rows: 32,
        scrollback: 1000,
      });
      terminal.open(container);

      const longTasks = collectLongTasks();
      const frames = collectFrameGaps();
      const writeCallbackMs = [];
      const sideEffects = createSideEffectMetrics();
      const heapStartBytes = performance.memory?.usedJSHeapSize ?? null;
      let pendingWrite = "";
      let inputChars = 0;
      let writeFlushCount = 0;
      const startedAt = performance.now();

      for (let index = 0; index < config.chunks; index += 1) {
        const chunk = buildChunk(scenario, index, config.chunkSize);
        inputChars += chunk.length;
        sideEffects.measure(chunk);
        pendingWrite += chunk;
        if (pendingWrite.length >= config.maxCharsPerFlush) {
          writeCallbackMs.push(await writeTerminal(terminal, pendingWrite));
          writeFlushCount += 1;
          pendingWrite = "";
        }
      }

      if (pendingWrite.length > 0) {
        writeCallbackMs.push(await writeTerminal(terminal, pendingWrite));
        writeFlushCount += 1;
      }
      sideEffects.flushHistory();
      await nextFrame();
      const totalMs = performance.now() - startedAt;
      frames.stop();
      longTasks.stop();
      const heapEndBytes = performance.memory?.usedJSHeapSize ?? null;
      const tailSample = container.innerText.slice(-240);
      const xtermRows = container.querySelectorAll(".xterm-rows div").length;
      terminal.dispose();

      return {
        dom: {
          tailSample,
          xtermRows,
        },
        frames: summarizeFrames(frames.values),
        heap: {
          deltaBytes: heapStartBytes === null || heapEndBytes === null ? null : heapEndBytes - heapStartBytes,
          endBytes: heapEndBytes,
          startBytes: heapStartBytes,
        },
        input: {
          bytes: inputChars,
          chars: inputChars,
          chunkSize: config.chunkSize,
          chunks: config.chunks,
        },
        longTasks: summarizeLongTasks(longTasks.values),
        pass: tailSample.length > 0 && writeFlushCount > 0,
        scenario,
        sideEffects: sideEffects.summary(),
        timing: {
          charsPerSecond: inputChars / Math.max(totalMs / 1000, 0.001),
          totalMs,
          writeCallbackMs: percentileSummary(writeCallbackMs),
          writeFlushCount,
        },
        warnings: [],
      };
    }

    function writeTerminal(terminal, content) {
      const startedAt = performance.now();
      return new Promise((resolve) => {
        terminal.write(content, () => {
          resolve(performance.now() - startedAt);
        });
      });
    }

    function buildChunk(scenario, index, chunkSize) {
      const line = "line-" + String(index).padStart(5, "0") + " ";
      const payload = (line + "x".repeat(Math.max(1, chunkSize - line.length - 2))).slice(0, chunkSize - 2) + "\\r\\n";
      if (scenario === "plain") {
        return payload;
      }
      if (scenario === "osc") {
        return "\\u001b]7;file://localhost/home/kerminal/" + index + "\\u0007" + payload;
      }
      if (scenario === "long-line") {
        return "long-" + String(index).padStart(5, "0") + "-" + "y".repeat(chunkSize * 2) + "\\r\\n";
      }
      if (index % 10 === 0) {
        return "\\u001b]7;file://localhost/work/mixed/" + index + "\\u0007" + payload;
      }
      if (index % 3 === 0) {
        return "$ command-" + index + "\\r\\n" + payload;
      }
      return payload;
    }

    function createSideEffectMetrics() {
      let commandBlockAppendMs = 0;
      let commandBlockTail = "";
      let cwdPathCount = 0;
      let historyAppendMs = 0;
      let historyFlushCount = 0;
      let historyLength = 0;
      let oscParseMs = 0;
      let pendingHistory = [];
      let remotePrewarmSchedules = 0;

      return {
        flushHistory() {
          if (pendingHistory.length === 0) {
            return;
          }
          const startedAt = performance.now();
          historyLength += pendingHistory.join("").length;
          pendingHistory = [];
          historyAppendMs += performance.now() - startedAt;
          historyFlushCount += 1;
        },
        measure(chunk) {
          let startedAt = performance.now();
          if (chunk.includes("\\u001b]7;")) {
            const matches = chunk.matchAll(/\\u001b\\]7;file:\\/\\/[^\\u0007]+\\u0007/g);
            for (const match of matches) {
              cwdPathCount += 1;
              remotePrewarmSchedules += 1;
              void match;
            }
          }
          oscParseMs += performance.now() - startedAt;

          startedAt = performance.now();
          commandBlockTail = (commandBlockTail + chunk).slice(-20000);
          commandBlockAppendMs += performance.now() - startedAt;

          startedAt = performance.now();
          pendingHistory.push(chunk);
          if (pendingHistory.length >= 50) {
            historyLength += pendingHistory.join("").length;
            pendingHistory = [];
            historyFlushCount += 1;
          }
          historyAppendMs += performance.now() - startedAt;
        },
        summary() {
          return {
            commandBlockAppendMs,
            commandBlockTailLength: commandBlockTail.length,
            cwdPathCount,
            historyAppendMs,
            historyFlushCount,
            historyLength,
            oscParseMs,
            remotePrewarmSchedules,
          };
        },
      };
    }

    function collectFrameGaps() {
      const values = [];
      let last = performance.now();
      let running = true;
      function tick(now) {
        values.push(now - last);
        last = now;
        if (running) {
          requestAnimationFrame(tick);
        }
      }
      requestAnimationFrame(tick);
      return {
        stop() {
          running = false;
        },
        values,
      };
    }

    function collectLongTasks() {
      const values = [];
      if (!("PerformanceObserver" in window) || !PerformanceObserver.supportedEntryTypes?.includes("longtask")) {
        return {
          stop() {},
          values,
        };
      }
      const observer = new PerformanceObserver((list) => {
        for (const entry of list.getEntries()) {
          values.push(entry.duration);
        }
      });
      observer.observe({ entryTypes: ["longtask"] });
      return {
        stop() {
          observer.disconnect();
        },
        values,
      };
    }

    function summarizeFrames(values) {
      return {
        count: values.length,
        gapMs: percentileSummary(values),
        over16ms: values.filter((value) => value > 16.7).length,
        over50ms: values.filter((value) => value > 50).length,
      };
    }

    function summarizeLongTasks(values) {
      return {
        count: values.length,
        maxMs: values.length === 0 ? 0 : Math.max(...values),
        totalMs: values.reduce((sum, value) => sum + value, 0),
      };
    }

    function percentileSummary(values) {
      if (values.length === 0) {
        return { max: 0, p50: 0, p95: 0, p99: 0 };
      }
      const sorted = [...values].sort((left, right) => left - right);
      return {
        max: sorted.at(-1),
        p50: percentile(sorted, 0.5),
        p95: percentile(sorted, 0.95),
        p99: percentile(sorted, 0.99),
      };
    }

    function percentile(sorted, ratio) {
      return sorted[Math.min(sorted.length - 1, Math.floor((sorted.length - 1) * ratio))];
    }

    function nextFrame() {
      return new Promise((resolve) => requestAnimationFrame(() => resolve()));
    }
  </script>
</body>
</html>`;
}

await main();

import { describe, expect, it } from "vitest";
import type { MachineGroup } from "../workspace/types";
import { buildVisibleMachineGroups } from "./machineSidebarVisibilityModel";

describe("buildVisibleMachineGroups", () => {
  it("keeps the original groups when there is no search", () => {
    const groups = largeMachineGroups(3, 4);

    expect(buildVisibleMachineGroups(groups, "")).toBe(groups);
  });

  it("keeps all machines when the group title matches", () => {
    const groups = largeMachineGroups(2, 3);

    const visibleGroups = buildVisibleMachineGroups(groups, "group 1");

    expect(visibleGroups).toHaveLength(1);
    expect(visibleGroups[0]?.id).toBe("group-1");
    expect(visibleGroups[0]?.machines).toHaveLength(3);
  });

  it("filters machines by name description and tags", () => {
    const groups = largeMachineGroups(2, 4);

    const visibleByName = buildVisibleMachineGroups(groups, "host-1-2");
    const visibleByDescription = buildVisibleMachineGroups(groups, "10.0.1.3");
    const visibleByTag = buildVisibleMachineGroups(groups, "batch-3");

    expect(visibleByName).toHaveLength(1);
    expect(visibleByName[0]?.machines.map((machine) => machine.id)).toEqual([
      "machine-1-2",
    ]);
    expect(visibleByDescription[0]?.machines.map((machine) => machine.id)).toEqual([
      "machine-1-3",
    ]);
    expect(visibleByTag.flatMap((group) => group.machines)).toHaveLength(2);
  });

  it("handles a large host tree without mutating the source groups", () => {
    const groups = largeMachineGroups(20, 100);

    const visibleGroups = buildVisibleMachineGroups(groups, "batch-42");

    expect(visibleGroups).toHaveLength(20);
    expect(visibleGroups.flatMap((group) => group.machines)).toHaveLength(20);
    expect(groups[0]?.machines).toHaveLength(100);
  });
});

function largeMachineGroups(
  groupCount: number,
  machinesPerGroup: number,
): MachineGroup[] {
  return Array.from({ length: groupCount }, (_, groupIndex) => ({
    id: `group-${groupIndex}`,
    machines: Array.from({ length: machinesPerGroup }, (_, machineIndex) => ({
      description: `deploy@10.0.${groupIndex}.${machineIndex}:22`,
      host: `10.0.${groupIndex}.${machineIndex}`,
      id: `machine-${groupIndex}-${machineIndex}`,
      kind: "ssh" as const,
      name: `host-${groupIndex}-${machineIndex}`,
      port: 22,
      remoteGroupId: `group-${groupIndex}`,
      status: "offline" as const,
      tags: ["ssh", `batch-${machineIndex}`],
      username: "deploy",
    })),
    title: `Group ${groupIndex}`,
  }));
}

/**
 * Machine sidebar visibility model.
 *
 * @author kongweiguang
 */

import type { Machine, MachineGroup } from "../workspace/types";

export function buildVisibleMachineGroups(
  groups: MachineGroup[],
  normalizedSearch: string,
): MachineGroup[] {
  if (!normalizedSearch) {
    return groups;
  }

  return groups
    .map((group) => {
      const groupMatches = group.title.toLowerCase().includes(normalizedSearch);
      if (groupMatches) {
        return group;
      }

      return {
        ...group,
        machines: group.machines.filter((machine) =>
          machineMatchesSearch(machine, normalizedSearch),
        ),
      };
    })
    .filter((group) => {
      return (
        group.title.toLowerCase().includes(normalizedSearch) ||
        group.machines.length > 0
      );
    });
}

function machineMatchesSearch(machine: Machine, normalizedSearch: string) {
  const haystack = `${machine.name} ${machine.description} ${machine.tags.join(" ")}`;
  return haystack.toLowerCase().includes(normalizedSearch);
}

