} from "./terminalOutputInstrumentation";

const GLOBAL_KEY = "__kerminalTerminalOutputInstrumentation";

function setGlobalInstrumentation(
  state: TerminalOutputInstrumentationState | undefined,
) {
  Object.defineProperty(globalThis, GLOBAL_KEY, {
    configurable: true,
    value: state,
  });
}

describe("terminalOutputInstrumentation", () => {
  afterEach(() => {
    Reflect.deleteProperty(globalThis, GLOBAL_KEY);
  });

  it("is disabled by default", () => {
    const instrumentation = createTerminalOutputInstrumentation({
      paneId: "pane-1",
    });

    expect(instrumentation).toBeNull();
    expect(
      runTerminalOutputInstrumentationStep(
        instrumentation,
        "writer",
        12,
        () => "written",
      ),
    ).toBe("written");
  });

  it("aggregates counts, chars, and durations when enabled", () => {
    const state: TerminalOutputInstrumentationState = { enabled: true };
    setGlobalInstrumentation(state);
    const instrumentation = createTerminalOutputInstrumentation({
      paneId: "pane-1",
    });

    runTerminalOutputInstrumentationStep(
      instrumentation,
      "commandBlock",
      5,
      () => undefined,
    );
    runTerminalOutputInstrumentationStep(
      instrumentation,
      "commandBlock",
      7,
      () => undefined,
    );

    expect(state.buckets?.commandBlock).toMatchObject({
      count: 2,
      totalChars: 12,
    });
    expect(state.buckets?.commandBlock?.totalMs).toBeGreaterThanOrEqual(0);
    expect(state.buckets?.commandBlock?.maxMs).toBeGreaterThanOrEqual(0);
  });
});

// @author kongweiguang

export type TerminalOutputInstrumentationStep =
  | "commandBlock"
  | "cwdOsc"
  | "history"
  | "remotePrewarmGit"
  | "remotePrewarmPath"
  | "writer";

export interface TerminalOutputInstrumentationBucket {
  count: number;
  maxMs: number;
  totalChars: number;
  totalMs: number;
}

export interface TerminalOutputInstrumentationState {
  enabled?: boolean;
  buckets?: Partial<
    Record<TerminalOutputInstrumentationStep, TerminalOutputInstrumentationBucket>
  >;
}

export interface TerminalOutputInstrumentation {
  measure<T>(
    step: TerminalOutputInstrumentationStep,
    chars: number,
    action: () => T,
  ): T;
}

interface TerminalOutputInstrumentationOptions {
  paneId: string;
}

const TERMINAL_OUTPUT_INSTRUMENTATION_GLOBAL =
  "__kerminalTerminalOutputInstrumentation";

function nowMs() {
  if (
    typeof globalThis.performance !== "undefined" &&
    typeof globalThis.performance.now === "function"
  ) {
    return globalThis.performance.now();
  }
  return Date.now();
}

function resolveInstrumentationState():
  | TerminalOutputInstrumentationState
  | undefined {
  const target = globalThis as unknown as Record<
    string,
    TerminalOutputInstrumentationState | undefined
  >;
  return target[TERMINAL_OUTPUT_INSTRUMENTATION_GLOBAL];
}

export function createTerminalOutputInstrumentation({
  paneId: _paneId,
}: TerminalOutputInstrumentationOptions): TerminalOutputInstrumentation | null {
  const state = resolveInstrumentationState();
  if (!state?.enabled) {
    return null;
  }
  state.buckets ??= {};

  return {
    measure(step, chars, action) {
      if (!state.enabled) {
        return action();
      }
      const start = nowMs();
      try {
        return action();
      } finally {
        const durationMs = Math.max(0, nowMs() - start);
        const bucket = (state.buckets![step] ??= {
          count: 0,
          maxMs: 0,
          totalChars: 0,
          totalMs: 0,
        });
        bucket.count += 1;
        bucket.totalChars += Math.max(0, chars);
        bucket.totalMs += durationMs;
        bucket.maxMs = Math.max(bucket.maxMs, durationMs);
      }
    },
  };
}

export function runTerminalOutputInstrumentationStep<T>(
  instrumentation: TerminalOutputInstrumentation | null,
  step: TerminalOutputInstrumentationStep,
  chars: number,
  action: () => T,
): T {
  if (!instrumentation) {
    return action();
  }
  return instrumentation.measure(step, chars, action);
}

import { describe, expect, it, vi } from "vitest";
import type { AiChatStreamStep } from "../../../lib/aiAgentApi";
import { createAiStreamingMessageBuffer } from "./aiStreamingMessageBuffer";
import type { ConversationState } from "./aiToolContentModel";

function createManualTimer() {
  const callbacks = new Map<
    ReturnType<typeof globalThis.setTimeout>,
    () => void
  >();
  let nextHandle = 1;
  const timer = {
    clearTimeout: vi.fn((timerId: ReturnType<typeof globalThis.setTimeout>) => {
      callbacks.delete(timerId);
    }),
    setTimeout: vi.fn((callback: () => void) => {
      const handle =
        nextHandle as unknown as ReturnType<typeof globalThis.setTimeout>;
      nextHandle += 1;
      callbacks.set(handle, callback);
      return handle;
    }),
  };

  return {
    pendingCount: () => callbacks.size,
    runNext() {
      const next = callbacks.entries().next();
      if (next.done) {
        return false;
      }
      const [handle, callback] = next.value;
      callbacks.delete(handle);
      callback();
      return true;
    },
    timer,
  };
}

function createConversationState(): ConversationState {
  return {
    activeConversationId: "conversation-1",
    conversations: [
      {
        createdAt: 1,
        id: "conversation-1",
        messages: [
          {
            content: "",
            createdAt: 2,
            id: "assistant-1",
            processSteps: [],
            role: "assistant",
            status: "streaming",
          },
        ],
        title: "Test",
        updatedAt: 1,
      },
    ],
  };
}

function assistantMessage(state: ConversationState) {
  return state.conversations[0]?.messages[0];
}

describe("aiStreamingMessageBuffer", () => {
  it("coalesces delta bursts into one conversation update", () => {
    const manual = createManualTimer();
    let state = createConversationState();
    let updates = 0;
    const buffer = createAiStreamingMessageBuffer({
      applyConversationUpdate: (update) => {
        updates += 1;
        state = update(state);
      },
      conversationId: "conversation-1",
      flushDelayMs: 32,
      messageId: "assistant-1",
      timer: manual.timer,
    });

    for (let index = 0; index < 1000; index += 1) {
      buffer.appendDelta(`${index % 10}`);
    }

    expect(updates).toBe(0);
    expect(buffer.pendingFlush()).toBe(true);
    expect(buffer.pendingDeltaLength()).toBe(1000);
    expect(manual.timer.setTimeout).toHaveBeenCalledTimes(1);

    expect(manual.runNext()).toBe(true);

    expect(updates).toBe(1);
    expect(assistantMessage(state)?.content).toBe(
      Array.from({ length: 1000 }, (_, index) => `${index % 10}`).join(""),
    );
    expect(buffer.pendingFlush()).toBe(false);
    expect(manual.pendingCount()).toBe(0);
  });

  it("flushes pending deltas before applying a process step", () => {
    const manual = createManualTimer();
    let state = createConversationState();
    const updates: string[] = [];
    const buffer = createAiStreamingMessageBuffer({
      applyConversationUpdate: (update) => {
        state = update(state);
        const message = assistantMessage(state);
        updates.push(
          `${message?.content ?? ""}|${message?.processSteps?.[0]?.title ?? ""}`,
        );
      },
      conversationId: "conversation-1",
      messageId: "assistant-1",
      timer: manual.timer,
    });
    const step: AiChatStreamStep = {
      id: "provider",
      status: "active",
      title: "等待模型响应",
    };

    buffer.appendDelta("hello ");
    buffer.appendDelta("world");
    buffer.applyStep(step);

    expect(updates).toEqual(["hello world|", "hello world|等待模型响应"]);
    expect(assistantMessage(state)).toMatchObject({
      content: "hello world",
      processSteps: [step],
      status: "streaming",
    });
    expect(manual.pendingCount()).toBe(0);
  });

  it("flushes pending deltas on dispose and ignores later input", () => {
    const manual = createManualTimer();
    let state = createConversationState();
    let updates = 0;
    const buffer = createAiStreamingMessageBuffer({
      applyConversationUpdate: (update) => {
        updates += 1;
        state = update(state);
      },
      conversationId: "conversation-1",
      messageId: "assistant-1",
      timer: manual.timer,
    });

    buffer.appendDelta("final");
    buffer.dispose();
    buffer.appendDelta(" ignored");
    manual.runNext();

    expect(updates).toBe(1);
    expect(assistantMessage(state)?.content).toBe("final");
    expect(buffer.pendingFlush()).toBe(false);
  });
});

