import type { AiChatStreamStep } from "../../../lib/aiAgentApi";
import {
  updateConversationMessage,
  upsertProcessStep,
  type ConversationState,
} from "./aiToolContentModel";

type TimerId = ReturnType<typeof globalThis.setTimeout>;

export interface AiStreamingMessageBufferTimer {
  clearTimeout(timerId: TimerId): void;
  setTimeout(callback: () => void, delayMs: number): TimerId;
}

interface AiStreamingMessageBufferOptions {
  applyConversationUpdate(update: (state: ConversationState) => ConversationState): void;
  conversationId: string;
  flushDelayMs?: number;
  messageId: string;
  timer?: AiStreamingMessageBufferTimer;
}

const DEFAULT_AI_STREAMING_FLUSH_DELAY_MS = 32;

const globalTimer: AiStreamingMessageBufferTimer = {
  clearTimeout: (timerId) => globalThis.clearTimeout(timerId),
  setTimeout: (callback, delayMs) => globalThis.setTimeout(callback, delayMs),
};

export function createAiStreamingMessageBuffer({
  applyConversationUpdate,
  conversationId,
  flushDelayMs = DEFAULT_AI_STREAMING_FLUSH_DELAY_MS,
  messageId,
  timer = globalTimer,
}: AiStreamingMessageBufferOptions) {
  let disposed = false;
  let flushTimer: TimerId | null = null;
  let pendingDelta = "";

  const cancelScheduledFlush = () => {
    if (flushTimer === null) {
      return;
    }
    timer.clearTimeout(flushTimer);
    flushTimer = null;
  };

  const flush = () => {
    cancelScheduledFlush();
    if (!pendingDelta) {
      return false;
    }
    const delta = pendingDelta;
    pendingDelta = "";
    applyConversationUpdate((current) =>
      updateConversationMessage(current, conversationId, messageId, (draft) => ({
        ...draft,
        content: draft.content + delta,
        status: "streaming",
      })),
    );
    return true;
  };

  const scheduleFlush = () => {
    if (disposed || flushTimer !== null) {
      return;
    }
    flushTimer = timer.setTimeout(() => {
      flushTimer = null;
      if (!disposed) {
        flush();
      }
    }, Math.max(0, flushDelayMs));
  };

  return {
    appendDelta(delta: string) {
      if (disposed || !delta) {
        return;
      }
      pendingDelta += delta;
      scheduleFlush();
    },
    applyStep(step: AiChatStreamStep) {
      if (disposed) {
        return;
      }
      flush();
      applyConversationUpdate((current) =>
        updateConversationMessage(current, conversationId, messageId, (draft) => ({
          ...draft,
          processSteps: upsertProcessStep(draft.processSteps, step),
          status: step.status === "error" ? "error" : "streaming",
        })),
      );
    },
    dispose() {
      if (disposed) {
        return;
      }
      flush();
      disposed = true;
    },
    flush,
    pendingDeltaLength() {
      return pendingDelta.length;
    },
    pendingFlush() {
      return flushTimer !== null;
    },
  };
}

import { fireEvent, render } from "@testing-library/react";
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import {
  AI_CONVERSATION_PERSISTENCE_DEBOUNCE_MS,
  useDebouncedConversationPersistence,
} from "./useDebouncedConversationPersistence";
import type { ConversationState } from "./aiToolContentModel";

const CONVERSATION_STORAGE_KEY = "kerminal.ai.conversations.v1";

function conversationState(content: string): ConversationState {
  return {
    activeConversationId: "conversation-1",
    conversations: [
      {
        createdAt: 1,
        id: "conversation-1",
        messages: [
          {
            content,
            createdAt: 2,
            id: "user-1",
            role: "user",
          },
        ],
        title: "Test",
        updatedAt: 3,
      },
    ],
  };
}

function PersistenceHost({ state }: { state: ConversationState }) {
  useDebouncedConversationPersistence(state);
  return null;
}

describe("useDebouncedConversationPersistence", () => {
  beforeEach(() => {
    window.localStorage.clear();
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
    vi.restoreAllMocks();
  });

  it("coalesces rapid conversation state changes into one localStorage write", () => {
    const setItemSpy = vi.spyOn(Storage.prototype, "setItem");
    const { rerender } = render(
      <PersistenceHost state={conversationState("first")} />,
    );
    setItemSpy.mockClear();

    rerender(<PersistenceHost state={conversationState("second")} />);
    rerender(<PersistenceHost state={conversationState("third")} />);

    expect(setItemSpy).not.toHaveBeenCalled();

    vi.advanceTimersByTime(AI_CONVERSATION_PERSISTENCE_DEBOUNCE_MS - 1);
    expect(setItemSpy).not.toHaveBeenCalled();

    vi.advanceTimersByTime(1);

    expect(setItemSpy).toHaveBeenCalledTimes(1);
    const saved = window.localStorage.getItem(CONVERSATION_STORAGE_KEY);
    expect(saved).toContain("third");
    expect(saved).not.toContain("second");
  });

  it("flushes the latest conversation state on pagehide", () => {
    const setItemSpy = vi.spyOn(Storage.prototype, "setItem");
    const { rerender } = render(
      <PersistenceHost state={conversationState("first")} />,
    );
    setItemSpy.mockClear();

    rerender(<PersistenceHost state={conversationState("latest before hide")} />);
    fireEvent(window, new Event("pagehide"));

    expect(setItemSpy).toHaveBeenCalledTimes(1);
    expect(window.localStorage.getItem(CONVERSATION_STORAGE_KEY)).toContain(
      "latest before hide",
    );
  });
});

